   192→// Implementation of a HTTP dynamic filter config provider.
   193→// NeutralHttpFilterConfigFactory can either be a NamedHttpFilterConfigFactory
   194→// or an UpstreamHttpFilterConfigFactory.
   195→template <class FactoryCtx, class NeutralHttpFilterConfigFactory>
   196→class HttpDynamicFilterConfigProviderImpl
   197→    : public DynamicFilterConfigProviderImpl<NamedHttpFilterFactoryCb> {
   198→public:
   199→  HttpDynamicFilterConfigProviderImpl(
   200→      FilterConfigSubscriptionSharedPtr& subscription,
   201→      const absl::flat_hash_set<std::string>& require_type_urls,
   202→      Server::Configuration::ServerFactoryContext& server_context, FactoryCtx& factory_context,
   203→      ProtobufTypes::MessagePtr&& default_config, bool last_filter_in_filter_chain,
   204→      const std::string& filter_chain_type, absl::string_view stat_prefix,
   205→      const Network::ListenerFilterMatcherSharedPtr& listener_filter_matcher)
   206→      : DynamicFilterConfigProviderImpl(subscription, require_type_urls,
   207→                                        server_context.threadLocal(), std::move(default_config),
   208→                                        last_filter_in_filter_chain, filter_chain_type, stat_prefix,
   209→                                        listener_filter_matcher),
   210→        server_context_(server_context), factory_context_(factory_context) {}
   211→  void validateMessage(const std::string& config_name, const Protobuf::Message& message,
   212→                       const std::string& factory_name) const override {
   213→    auto* factory =
   214→        Registry::FactoryRegistry<NeutralHttpFilterConfigFactory>::getFactory(factory_name);
   215→    const bool is_terminal_filter = factory->isTerminalFilterByProto(message, server_context_);
   216→    Config::Utility::validateTerminalFilters(config_name, factory_name, filter_chain_type_,
   217→                                             is_terminal_filter, last_filter_in_filter_chain_);
   218→  }
   219→
   220→private:
   221→  absl::StatusOr<NamedHttpFilterFactoryCb>
   222→  instantiateFilterFactory(const Protobuf::Message& message) const override {
   223→    auto* factory = Registry::FactoryRegistry<NeutralHttpFilterConfigFactory>::getFactoryByType(
   224→        message.GetTypeName());
   225→    absl::StatusOr<Http::FilterFactoryCb> error_or_factory =
   226→        factory->createFilterFactoryFromProto(message, getStatPrefix(), factory_context_);
   227→    RETURN_IF_STATUS_NOT_OK(error_or_factory);
   228→    return NamedHttpFilterFactoryCb{factory->name(), error_or_factory.value()};
   229→  }
   230→
   231→  Server::Configuration::ServerFactoryContext& server_context_;
   232→  FactoryCtx& factory_context_;
   233→};
